const input = $input.first().json;
const query      = (input.query || input.message || input.text || '').trim();
const chatId     = (input.chatId || input.chat_id || '').toString();
const params     = input.params || {};
const leadName   = (input.lead_name   || params.lead_name   || '').trim();
const leadStatus = (input.lead_status || params.lead_status || '').trim();
const value      = input.value || params.value || null;
const date       = input.date  || params.date  || null;
const sheet      = input.sheet || params.sheet || null;

const now  = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const dd   = String(now.getDate()).padStart(2, '0');
const mm   = String(now.getMonth() + 1).padStart(2, '0');
const yyyy = now.getFullYear();
const today = `${dd}/${mm}/${yyyy}`;   // SIEMPRE DD/MM/YYYY → "20/02/2026"
const hour  = String(now.getHours()).padStart(2,'0') + ':' + String(now.getMinutes()).padStart(2,'0');
const month = now.toLocaleString('es-CO', { month: 'long' });
const sheetMonth = month.charAt(0).toUpperCase() + month.slice(1) + ' ' + yyyy;

return { json: {
  query, chatId, params, leadName, leadStatus, value, date, sheet,
  today, hour, month, year: yyyy, sheetMonth
}};

