// 🔗 BRIDGE v4.0
const agentRaw = $input.first().json;
const parser   = $('📦 Parser1').first().json;

let ai = {};
try {
  let text = agentRaw.text || agentRaw.output || agentRaw.message || '';
  if (typeof text === 'object') { ai = text; }
  else {
    text = text.replace(/[`]{3}json\s*/gi,'').replace(/[`]{3}\s*/gi,'').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) ai = JSON.parse(m[0]);
  }
} catch(e) { ai = { action: 'read_kpis' }; }

const p = ai.params || {};

return [{ json: {
  action:             ai.action || 'read_kpis',
  sheet_system:       ai.sheet_system || 'tracking',
  sheet_name:         ai.sheet_name || 'Registro 2026',
  intent_description: ai.intent_description || '',
  confidence:         ai.confidence || 'medium',
  // write_kpi
  field:    p.field || '',
  value:    p.value ?? null,
  // agendados
  nombre:            p.nombre || parser.leadName || '',
  nicho:             p.nicho || '',
  hora:              p.hora || '',
  fechaAgendamiento: p.fecha_agendamiento || parser.today,
  detalles:          p.detalles || '',
  enlaceRecurso:     p.enlace_recurso || '',
  correo:            p.correo || '',
  telefono:          p.telefono || '',
  fuente:            p.fuente || 'Manual',
  cerrado:           p.cerrado ?? null,
  ingreso:           p.ingreso ?? null,
  motivoNoCierre:    p.motivo_no_cierre || '',
  // onboarding
  datosCompletos:    p.datos_completos ?? false,
  // contexto
  query:   parser.query,
  chatId:  parser.chatId,
  today:   parser.today,
  hour:    parser.hour,
  Fecha:   parser.today
}}];

// 🔥 MEGA PREP WRITE v4.0 — DEFINITIVO
// Salida: EXACTAMENTE 2 keys → { Fecha: "DD/MM/YYYY", [Columna]: valor }
// autoMapInputData escribirá solo esas 2 celdas. Nada más.

const b = $('🔗 Bridge1').first().json;

// ── Fecha en formato EXACTO del sheet: DD/MM/YYYY ──────────────────
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const dd   = String(now.getDate()).padStart(2, '0');
const mm   = String(now.getMonth() + 1).padStart(2, '0');
const yyyy = now.getFullYear();
const fechaHoy = `${dd}/${mm}/${yyyy}`;  // → "20/02/2026"

// ── Columnas válidas (títulos EXACTOS B4:N4) ───────────────────────
const COLUMNAS_VALIDAS = new Set([
  'Meta de Mensajes',
  'Chats Iniciados en Instagram',
  'Faltan/Estado',
  'Respuestas',
  'Registrados',
  'Por Registrar',
  'Por Contestar',
  'Seguimientos',
  'Tasa de Resp.',
  'Agendados',
  'Tasa de Mensaje a Llamada',
  'Detalles de Agendados'
]);

// ── Keywords → Columna exacta ─────────────────────────────────────
// Orden: de más específico a menos específico
const KEYWORDS = [
  // Por Registrar (va antes de Registrad para evitar falsos positivos)
  { k: 'por registrar',               col: 'Por Registrar' },
  { k: 'faltan',                      col: 'Por Registrar' },
  { k: 'falta registrar',             col: 'Por Registrar' },
  // Por Contestar
  { k: 'por contestar',               col: 'Por Contestar' },
  { k: 'pendiente',                   col: 'Por Contestar' },
  { k: 'falta contestar',             col: 'Por Contestar' },
  // Chats Iniciados
  { k: 'chat',                        col: 'Chats Iniciados en Instagram' },
  { k: 'inicié',                      col: 'Chats Iniciados en Instagram' },
  { k: 'inicie',                      col: 'Chats Iniciados en Instagram' },
  { k: 'contacté',                    col: 'Chats Iniciados en Instagram' },
  { k: 'contacte',                    col: 'Chats Iniciados en Instagram' },
  { k: 'mandé',                       col: 'Chats Iniciados en Instagram' },
  { k: 'mande',                       col: 'Chats Iniciados en Instagram' },
  { k: 'envié',                       col: 'Chats Iniciados en Instagram' },
  { k: 'envie',                       col: 'Chats Iniciados en Instagram' },
  { k: 'mensajes',                    col: 'Chats Iniciados en Instagram' },
  { k: 'leads contactados',           col: 'Chats Iniciados en Instagram' },
  // Respuestas (contest van antes de registr)
  { k: 'contestó',                    col: 'Respuestas' },
  { k: 'contesto',                    col: 'Respuestas' },
  { k: 'contest',                     col: 'Respuestas' },
  { k: 'respuest',                    col: 'Respuestas' },
  { k: 'respondier',                  col: 'Respuestas' },
  { k: 'respondio',                   col: 'Respuestas' },
  { k: 'respondió',                   col: 'Respuestas' },
  { k: 'me contestaron',              col: 'Respuestas' },
  // Registrados
  { k: 'registré',                    col: 'Registrados' },
  { k: 'registre',                    col: 'Registrados' },
  { k: 'registrado',                  col: 'Registrados' },
  { k: 'registré',                    col: 'Registrados' },
  // Detalles agendados (nombre = texto, va antes de "agend" numérico)
  { k: 'detalle',                     col: 'Detalles de Agendados' },
  { k: 'agendé a',                    col: 'Detalles de Agendados' },
  { k: 'agende a',                    col: 'Detalles de Agendados' },
  { k: 'nota:',                       col: 'Detalles de Agendados' },
  // Agendados numérico
  { k: 'agendé',                      col: 'Agendados' },
  { k: 'agende',                      col: 'Agendados' },
  { k: 'agendad',                     col: 'Agendados' },
  { k: 'cita',                        col: 'Agendados' },
  { k: 'llamada',                     col: 'Agendados' },
  // Seguimientos
  { k: 'seguimient',                  col: 'Seguimientos' },
  { k: 'follow',                      col: 'Seguimientos' },
  { k: 'seguí',                       col: 'Seguimientos' },
  { k: 'segui',                       col: 'Seguimientos' },
  // Meta
  { k: 'meta',                        col: 'Meta de Mensajes' },
  // Estado
  { k: 'estado',                      col: 'Faltan/Estado' },
];

// ── Normalizar texto (quitar tildes, minúsculas) ──────────────────
const norm = (s) => String(s || '').toLowerCase()
  .normalize('NFD').replace(/[̀-ͯ]/g, '');

// ── Resolver columna ──────────────────────────────────────────────
let columna = '';

// 1. El Clasificador dio un nombre válido → usarlo directo
if (b.field && COLUMNAS_VALIDAS.has(b.field)) {
  columna = b.field;
}

// 2. El Clasificador dio nombre inválido o vacío → buscar en query
if (!columna) {
  const q = norm(b.query);
  for (const { k, col } of KEYWORDS) {
    if (q.includes(norm(k))) {
      columna = col;
      break;
    }
  }
}

// 3. Sin columna → lanzar error descriptivo
if (!columna) {
  throw new Error(
    '❌ No identifiqué qué columna actualizar.\n' +
    'Sé más específico, por ejemplo:\n' +
    '• "registra 15 chats"\n' +
    '• "me contestó 1"\n' +
    '• "agendé 2 llamadas"\n' +
    '• "hice 5 seguimientos"'
  );
}

// ── Resolver valor ────────────────────────────────────────────────
let valor = b.value;

// Si el Clasificador no pasó valor, extraerlo del query
if (valor === null || valor === undefined || valor === '') {
  const match = (b.query || '').match(/\d+/);
  valor = match ? parseInt(match[0]) : null;
}

// Convertir a número (excepto columnas de texto)
const COLUMNAS_TEXTO = new Set(['Detalles de Agendados', 'Faltan/Estado']);
if (!COLUMNAS_TEXTO.has(columna) && valor !== null) {
  const num = parseFloat(String(valor));
  if (!isNaN(num)) valor = num;
}

if (valor === null || valor === undefined) {
  throw new Error(
    `❌ No encontré el valor para escribir en "${columna}".\n` +
    'Dime el número, por ejemplo: "me contestó 1", "agendé 2"'
  );
}

// ── OUTPUT FINAL: EXACTAMENTE 2 KEYS ─────────────────────────────
// autoMapInputData del Write KPI escribirá SOLO estas 2 celdas
const out = {};
out['Fecha'] = fechaHoy;
out[columna] = valor;

return [{ json: out }];

// 📊 RESPONSE BUILDER v4.0 — XUS Sheets
const bridge = $('🔗 Bridge1').first().json;
let items = [];
try { items = $input.all(); } catch(e) {}
const action = bridge.action;

const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const dd = String(now.getDate()).padStart(2,'0');
const mm = String(now.getMonth()+1).padStart(2,'0');
const fechaHoy = `${dd}/${mm}/${now.getFullYear()}`;

const normFecha = (f) => {
  if (!f) return '';
  const parts = String(f).trim().split('/');
  if (parts.length === 3) return parts[0].padStart(2,'0')+'/'+parts[1].padStart(2,'0')+'/'+parts[2];
  return String(f).trim();
};

let structuredData = {}, summary = '';

try {
  switch(action) {

    case 'read_kpis': {
      const rows = items.map(i => i.json).filter(r => r && r['Fecha']);
      const todayRow = rows.find(r => normFecha(r['Fecha']) === fechaHoy) || {};
      const encontrado = !!todayRow['Fecha'];
      const meta        = parseInt(todayRow['Meta de Mensajes'] || 80);
      const chats       = parseInt(todayRow['Chats Iniciados en Instagram'] || 0);
      const respuestas  = parseInt(todayRow['Respuestas'] || 0);
      const seguimientos= parseInt(todayRow['Seguimientos'] || 0);
      const agendados   = parseInt(todayRow['Agendados'] || 0);
      const porContestar= parseInt(todayRow['Por Contestar'] || 0);
      const porRegistrar= parseInt(todayRow['Por Registrar'] || 0);
      const registrados = parseInt(todayRow['Registrados'] || 0);
      const tasa        = chats > 0 ? ((respuestas/chats)*100).toFixed(1) : '0.0';
      const pctMeta     = meta  > 0 ? ((chats/meta)*100).toFixed(0) : '0';
      structuredData = { fecha: fechaHoy, encontrado, meta, chats, respuestas, seguimientos, agendados, porContestar, porRegistrar, registrados, tasa, pctMeta, detalles: todayRow['Detalles de Agendados'] || '' };
      summary = encontrado
        ? `KPIs ${fechaHoy}: ${chats}/${meta} chats (${pctMeta}% meta) | Respuestas: ${respuestas} | Tasa: ${tasa}% | Agendados: ${agendados} | Seguimientos: ${seguimientos} | Por Contestar: ${porContestar}`
        : `⚠️ No encontré fila para (${fechaHoy}). Filas: ${rows.length}. Última: ${normFecha(rows[rows.length-1]?.['Fecha']||'')}`;
      break;
    }

    case 'write_kpi': {
      structuredData = { success: true, field: bridge.field, value: bridge.value, date: fechaHoy };
      summary = `✅ "${bridge.field}" = ${bridge.value} → ${fechaHoy}`;
      break;
    }

    case 'add_agendado': {
      structuredData = { added: true, nombre: bridge.nombre, nicho: bridge.nicho, fecha: bridge.fechaAgendamiento, hora: bridge.hora };
      summary = `✅ Pipeline: "${bridge.nombre}" | ${bridge.nicho || 'Sin nicho'} | ${bridge.fechaAgendamiento} ${bridge.hora}`;
      break;
    }

    case 'update_agendado': {
      const tipo = bridge.cerrado === true ? '🎉 CIERRE' : bridge.cerrado === false ? '❌ NO CIERRE' : '📝 UPDATE';
      structuredData = { updated: true, nombre: bridge.nombre, cerrado: bridge.cerrado, ingreso: bridge.ingreso, motivo: bridge.motivoNoCierre };
      summary = bridge.cerrado === true
        ? `${tipo}: "${bridge.nombre}" cerró ✅ | $${bridge.ingreso || 0}`
        : bridge.cerrado === false
        ? `${tipo}: "${bridge.nombre}" — ${bridge.motivoNoCierre}`
        : `📝 "${bridge.nombre}" actualizado`;
      break;
    }

    case 'add_onboarding': {
      const item = items[0]?.json || {};
      structuredData = { added: true, id: item['ID'], nombre: item['Nombre'], estado: item['Estado'] };
      summary = `✅ Onboarding: "${item['Nombre']}" registrado | ID: ${item['ID']} | Estado: Nuevo`;
      break;
    }

    case 'read_pipeline': {
      const rows = items.map(i => i.json).filter(r => r && r['Nombre']);
      const total     = rows.length;
      const cerrados  = rows.filter(r => String(r['Cerrado']).toUpperCase() === 'TRUE').length;
      const agendadosP= rows.filter(r => String(r['Agendado']).toUpperCase() === 'TRUE').length;
      const pendientes= total - cerrados;
      const ingresoTotal = rows
        .filter(r => String(r['Cerrado']).toUpperCase() === 'TRUE')
        .reduce((s,r) => s+(parseFloat(String(r['Ingresa ($)']||'0').replace(/[^0-9.]/g,''))||0), 0);
      const recientes = rows.slice(-8).reverse().map(r => ({
        nombre: r['Nombre'], nicho: r['Nicho']||'',
        agendado: String(r['Agendado']).toUpperCase()==='TRUE',
        cerrado: String(r['Cerrado']).toUpperCase()==='TRUE',
        ingreso: parseFloat(String(r['Ingresa ($)']||'0').replace(/[^0-9.]/g,''))||0,
        fecha: normFecha(r['Fecha de Agendamiento']||r['Fecha de Contacto']||''),
        hora: r['Hora de Agendamiento']||'',
        detalle: r['Detalles']||'',
        noCierre: r['No cerrado']||''
      }));
      structuredData = { total, cerrados, agendadosP, pendientes, ingresoTotal, recientes };
      summary = `Pipeline: ${total} leads | ${agendadosP} agendados | ${cerrados} cerrados | ${pendientes} pendientes | $${ingresoTotal.toLocaleString()}`;
      break;
    }

    case 'query_revenue': {
      const rows = items.map(i => i.json).filter(r => r && r['Nombre']);
      const cerrados = rows.filter(r => String(r['Cerrado']).toUpperCase() === 'TRUE');
      const total    = cerrados.reduce((s,r) => s+(parseFloat(String(r['Ingresa ($)']||'0').replace(/[^0-9.]/g,''))||0), 0);
      const pct      = ((total/100000)*100).toFixed(1);
      const faltante = Math.max(0, 100000-total);
      const nichos   = {};
      cerrados.forEach(r => { if(r['Nicho']) nichos[r['Nicho']]=(nichos[r['Nicho']]||0)+1; });
      structuredData = { total, count: cerrados.length, pct, faltante, nichos };
      summary = `💰 Revenue: $${total.toLocaleString()} (${pct}% de $100K) | Faltan: $${faltante.toLocaleString()} | ${cerrados.length} cierres`;
      break;
    }

    case 'read_protocols': {
      const rows = items.map(i => i.json).filter(r => r && r['LeadID']);
      const byStatus = {};
      rows.forEach(r => { const s=r['Estado']||'Sin estado'; byStatus[s]=(byStatus[s]||0)+1; });
      const topScored = rows
        .filter(r => r['Score'])
        .sort((a,b) => parseFloat(b.Score||0)-parseFloat(a.Score||0))
        .slice(0,5)
        .map(r => ({ id: r['LeadID'], nombre: r['Nombre'], dolor: r['DolorPrincipal'], score: r['Score'], categoria: r['Categoria'], facturacion: r['Facturacion'] }));
      structuredData = { total: rows.length, byStatus, topScored };
      summary = `Protocolos: ${rows.length} leads | ${JSON.stringify(byStatus)} | Top leads: ${topScored.map(l=>l.nombre+' ('+l.score+')').join(', ')}`;
      break;
    }

    case 'read_onboarding': {
      const rows = items.map(i => i.json).filter(r => r && r['ID']);
      const pagados   = rows.filter(r => r['Pago Verificado (Y/N)'] === 'Y').length;
      const firmados  = rows.filter(r => r['Firma Verificada (Y/N)'] === 'Y').length;
      const sinFirma  = rows.filter(r => r['Firma Verificada (Y/N)'] !== 'Y').length;
      const recientes = rows.slice(-5).map(r => ({
        id: r['ID'], nombre: r['Nombre'], estado: r['Estado'],
        accion: r['Próxima Acción'], recordatorio: r['Recordatorio (Fecha)'],
        notas: r['Notas'], firma: r['Firma Verificada (Y/N)'], pago: r['Pago Verificado (Y/N)']
      }));
      structuredData = { total: rows.length, pagados, firmados, sinFirma, recientes };
      summary = `Onboarding: ${rows.length} clientes | ${pagados} pagados | ${firmados} con firma | ${sinFirma} sin firma`;
      break;
    }

    case 'read_nexus': {
      const rows = items.map(i => i.json).filter(r => r&&(r['business_name']||r['name']||r['nombre']));
      const t1=rows.filter(r=>r['tier']==='TIER 1').length;
      const t2=rows.filter(r=>r['tier']==='TIER 2').length;
      const t3=rows.filter(r=>r['tier']==='TIER 3').length;
      structuredData = { total: rows.length, tier1:t1, tier2:t2, tier3:t3,
        top10: rows.filter(r=>r['tier']==='TIER 1').slice(0,10).map(r=>({
          nombre: r['business_name']||r['name']||r['nombre'],
          rating: r['rating'], reviews: r['reviews_count'], notas: r['notas_investigacion']
        }))
      };
      summary = `Nexus: ${rows.length} total | TIER 1: ${t1} | TIER 2: ${t2} | TIER 3: ${t3}`;
      break;
    }

    default:
      summary = `Acción "${action}" procesada.`;
  }
} catch(e) {
  summary = '❌ Error: ' + e.message;
  structuredData = { error: true, message: e.message, action };
}

return [{ json: {
  action, intent_description: bridge.intent_description,
  query: bridge.query, chatId: bridge.chatId,
  today: fechaHoy, hour: bridge.hour,
  summary, data: structuredData, confidence: bridge.confidence
}}];

