const raw = $input.first().json;
const builder = $('📊 Response Builder1').first().json;

let final;
try {
  let text = raw.text || raw.output || raw.message || '';
  if (typeof text === 'object' && text.textResponse) { final = text; }
  else {
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/[`]{3}json\s*/gi, '').replace(/[`]{3}\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) final = JSON.parse(m[0]); else throw new Error('No JSON');
  }
} catch(e) {
  final = { textResponse: `✅ Procesado\n\n${builder.summary || 'Acción ejecutada.'}`, toolResponse: builder.summary || 'Sheets actualizado' };
}

return [{ json: { textResponse: final.textResponse || builder.summary, toolResponse: final.toolResponse || 'Sheets procesado', action: builder.action, data: builder.data, chatId: builder.chatId, success: true }}];

// 🔥 MEGA PREP AGENDADO v1.0
// Para add_agendado: construye fila completa lista para append
// Para update_agendado: construye objeto de actualización con matching por Nombre

const b = $('🔗 Bridge1').first().json;
const action = b.action;

// Fecha exacta DD/MM/YYYY
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const dd = String(now.getDate()).padStart(2,'0');
const mm = String(now.getMonth()+1).padStart(2,'0');
const fechaHoy = `${dd}/${mm}/${now.getFullYear()}`;

if (action === 'add_agendado') {
  // Construir fila nueva — todos los campos de Agendados/LEADS
  if (!b.nombre) {
    throw new Error('❌ Necesito el nombre del lead para agregarlo al pipeline.');
  }
  return [{ json: {
    'Fecha de Contacto':    fechaHoy,
    'Nombre':               b.nombre,
    'Enlace Recurso Enviado': b.enlaceRecurso || '',
    'Agendado':             'TRUE',
    'Hora de Agendamiento': b.hora || '',
    'Fecha de Agendamiento':b.fechaAgendamiento || fechaHoy,
    'Link de la Reunion':   '',
    'Nicho':                b.nicho || '',
    'Detalles':             b.detalles || '',
    'Cerrado':              'FALSE',
    'No cerrado':           '',
    'Ingresa ($)':          '',
    'Correo Electrónico':   b.correo || '',
    'Número Telefónico':    b.telefono || ''
  }}];
}

if (action === 'update_agendado') {
  // Actualización: solo campos que cambian + Nombre para el match
  if (!b.nombre) {
    throw new Error('❌ Necesito el nombre del lead para actualizar.');
  }
  const update = { 'Nombre': b.nombre };

  if (b.cerrado === true) {
    update['Cerrado'] = 'TRUE';
    update['No cerrado'] = '';
    if (b.ingreso !== null && b.ingreso !== undefined) {
      update['Ingresa ($)'] = b.ingreso;
    }
  } else if (b.cerrado === false) {
    update['Cerrado'] = 'FALSE';
    update['No cerrado'] = b.motivoNoCierre || 'No cerrado';
  }

  if (b.ingreso !== null && b.ingreso !== undefined && b.cerrado === null) {
    update['Ingresa ($)'] = b.ingreso;
  }

  return [{ json: update }];
}

// Fallback — no debería llegar aquí
return [{ json: { _skip: true } }];

// 🔥 MEGA PREP ONBOARDING v1.0
// Genera ID tipo NX-XXXXXXXX, valida datos obligatorios
// Si faltan datos → lanza error descriptivo pidiendo la info

const b = $('🔗 Bridge1').first().json;

// ── Generar ID estilo NX-ML7XXXXX ────────────────────────────────
const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
