function isComplete(v) {
  if (!v) return false;
  if (v === true || v === 1 || v === '1') return true;
  const n = String(v).trim().toUpperCase();
  return ['TRUE','VERDADERO','SI','SÍ','X','COMPLETO','✓','✔','1'].includes(n);
}

