const colKeys = allItems.length > 0 ? Object.keys(allItems[0].json) : [];
const matrix = {};

for (let d = 1; d <= Math.min(todayNum, 31); d++) {
  const dk = colKeys.find(k => k.trim() === String(d));
  if (!dk) continue;
  matrix[d] = { done: 0, total: 0, habits: [], weightedScore: 0, maxWeight: 0, revenueProtected: 0, revenueLost: 0 };

  allItems.forEach(item => {
    const r = item.json;
    const config = HABITS_CONFIG.find(h => h.row === r.row_number);
    if (!config) return;

    const completed = isComplete(r[dk]);
    matrix[d].total++;
    matrix[d].maxWeight += config.weight;

    if (completed) {
      matrix[d].done++;
      matrix[d].weightedScore += config.weight;
      matrix[d].revenueProtected += config.revenueImpact * DAILY_REVENUE_VALUE;
    } else {
      matrix[d].revenueLost += config.revenueImpact * DAILY_REVENUE_VALUE;
    }

    matrix[d].habits.push({
      name: config.name, completed, row: r.row_number,
      category: config.category, deadline: config.deadline,
      weight: config.weight, revenueImpact: config.revenueImpact,
      blockOrder: config.blockOrder,
      isPastDeadline: d === todayNum ? currentTimeDecimal > config.deadline : true,
      isLost: d === todayNum ? (currentTimeDecimal > config.deadline && !completed) : !completed
    });
  });
}

