// CÁLCULOS EN TIEMPO REAL (HOY)
// ═══════════════════════════════════════════════════════════════════════════

const today = matrix[todayNum] || { done: 0, total: 0, habits: [], weightedScore: 0, maxWeight: 0 };

const habitsShouldBeDone = today.habits.filter(h => h.isPastDeadline);
const habitsLost = today.habits.filter(h => h.isLost);
const habitsCompleted = today.habits.filter(h => h.completed);
const habitsPending = today.habits.filter(h => !h.completed && !h.isPastDeadline);

const expectedDoneCount = habitsShouldBeDone.length;
const actualDoneFromExpected = habitsShouldBeDone.filter(h => h.completed).length;
const realtimeRate = expectedDoneCount > 0 ? Math.round((actualDoneFromExpected / expectedDoneCount) * 100) : 100;

const totalDayPct = today.total > 0 ? Math.round((today.done / today.total) * 100) : 0;
const weightedPct = today.maxWeight > 0 ? Math.round((today.weightedScore / today.maxWeight) * 100) : 0;

const potentialMax = today.done + habitsPending.length;
const projectedPct = today.total > 0 ? Math.round((potentialMax / today.total) * 100) : 0;

const lostRevenueToday = habitsLost.reduce((s, h) => s + (h.revenueImpact * DAILY_REVENUE_VALUE), 0);
const protectedRevenueToday = habitsCompleted.reduce((s, h) => s + (h.revenueImpact * DAILY_REVENUE_VALUE), 0);
const pendingRevenueToday = habitsPending.reduce((s, h) => s + (h.revenueImpact * DAILY_REVENUE_VALUE), 0);

const hoursLeft = Math.max(0, 21.67 - currentTimeDecimal);
const habitsPerHour = hoursLeft > 0 ? (habitsPending.length / hoursLeft).toFixed(1) : 'N/A';

