let monthDone = 0, monthTotal = 0, monthWeighted = 0, monthMaxWeight = 0;
let monthRevenueLost = 0, monthRevenueProtected = 0;

Object.values(matrix).forEach(day => {
  monthDone += day.done;
  monthTotal += day.total;
  monthWeighted += day.weightedScore;
  monthMaxWeight += day.maxWeight;
  monthRevenueLost += day.revenueLost;
  monthRevenueProtected += day.revenueProtected;
});

const globalPct = monthTotal > 0 ? Math.round((monthDone / monthTotal) * 100) : 0;
const globalWeightedPct = monthMaxWeight > 0 ? Math.round((monthWeighted / monthMaxWeight) * 100) : 0;

// Rachas
let streak = 0;
for (let d = todayNum; d >= 1; d--) {
  if (matrix[d]) {
    const pct = matrix[d].total > 0 ? Math.round((matrix[d].done / matrix[d].total) * 100) : 0;
    if (pct >= 70) streak++; else break;
  } else break;
}

let bestStreak = 0, tempStreak = 0;
for (let d = 1; d <= todayNum; d++) {
  if (matrix[d]) {
    const pct = matrix[d].total > 0 ? Math.round((matrix[d].done / matrix[d].total) * 100) : 0;
    if (pct >= 70) { tempStreak++; if (tempStreak > bestStreak) bestStreak = tempStreak; }
    else tempStreak = 0;
  }
}

// Top fallas
const fails = {};
Object.values(matrix).forEach(day => {
  day.habits.forEach(h => { if (!h.completed) fails[h.name] = (fails[h.name] || 0) + 1; });
});
const topFails = Object.entries(fails).sort((a, b) => b[1] - a[1]).slice(0, 5);

// Tendencia 7 días
