    const pct = matrix[d].total > 0 ? Math.round((matrix[d].done / matrix[d].total) * 100) : 0;
    last7.push({ day: d, pct });
  }
}
const trend7avg = last7.length > 0 ? Math.round(last7.reduce((s, d) => s + d.pct, 0) / last7.length) : 0;
const trendDirection = last7.length >= 3 ? (last7[last7.length-1].pct > last7[0].pct ? '📈 SUBIENDO' : last7[last7.length-1].pct < last7[0].pct ? '📉 BAJANDO' : '➡️ ESTABLE') : '❓ INSUFICIENTE';

// Momentum score
const momentumFactors = {
  todayPct: totalDayPct * 0.3,
  realtimeRate: realtimeRate * 0.25,
  streak: Math.min(streak * 10, 100) * 0.2,
  trend: trend7avg * 0.15,
  weighted: weightedPct * 0.1
};
const momentum = Math.round(Object.values(momentumFactors).reduce((s, v) => s + v, 0));

// Rendimiento por categoría
const catStats = { matutino: {d:0,t:0}, business: {d:0,t:0}, cierre: {d:0,t:0} };
Object.values(matrix).forEach(day => {
  day.habits.forEach(h => {
