      else if (typeof rawDateObj === 'string') dateString = rawDateObj;
    }

    const deadline = dateString ? new Date(dateString) : null;
    const daysLeft = deadline ? Math.ceil((deadline - now) / (1000 * 60 * 60 * 24)) : 9999;

    // Icono inteligente
    const n = name.toLowerCase();
    let icon = '🎯';
    if (n.includes('usd') || n.includes('$') || n.includes('cliente') || n.includes('revenue')) icon = '💎';
    else if (n.includes('bmw') || n.includes('m4') || n.includes('carro')) icon = '🏎️';
    else if (n.includes('poblado') || n.includes('penthouse') || n.includes('apartamento')) icon = '🏙️';
    else if (n.includes('cartagena') || n.includes('viaje') || n.includes('trip')) icon = '✈️';
    else if (n.includes('iphone') || n.includes('mac') || n.includes('tech')) icon = '💻';
    else if (n.includes('seguidores') || n.includes('60k') || n.includes('instagram')) icon = '📸';
    else if (n.includes('lead') || n.includes('venta')) icon = '📈';
    else if (n.includes('salud') || n.includes('gym') || n.includes('peso')) icon = '💪';

    // Urgencia
    let urgency = '🟢 TIEMPO';
    if (daysLeft < 0) { urgency = '💀 VENCIDO'; overdueProjects++; criticalProjects++; }
    else if (daysLeft === 0) { urgency = '🚨 HOY'; criticalProjects++; }
    else if (daysLeft <= 7) { urgency = '🔴 ESTA SEMANA'; criticalProjects++; }
    else if (daysLeft <= 30) { urgency = '🟡 ESTE MES'; projectsThisMonth++; }
    else if (daysLeft <= 60) { urgency = '🟢 2 MESES'; }

    return {
      name, daysLeft, icon, urgency, status,
      deadline: dateString,
      isCompleted: status.toLowerCase().includes('completado') || status.toLowerCase().includes('done'),
      isActive: !status.toLowerCase().includes('completado') && !status.toLowerCase().includes('done')
    };
  });

  // Filtrar y ordenar
  projects = projects.filter(p => p.isActive);
  projects.sort((a, b) => a.daysLeft - b.daysLeft);

  // Deduplicar
  const seen = new Set();
  projects = projects.filter(p => {
    if (seen.has(p.name)) return false;
    seen.add(p.name);
    return true;
  });

} catch(e) {
  projects = [];
