} else {
  habitsPending.forEach(h => {
    const deadlineStr = Math.floor(h.deadline) + ':' + String(Math.round((h.deadline % 1) * 60)).padStart(2, '0');
    const timeLeft = h.deadline - currentTimeDecimal;
    const urg = timeLeft < 1 ? '🔴 URGENTE' : timeLeft < 2 ? '🟡 PRONTO' : '🟢 TIEMPO';
    ctx += '  ' + urg + ' ' + h.name + ' (hasta ' + deadlineStr + ', $' + Math.round(h.revenueImpact * DAILY_REVENUE_VALUE) + ')\n';
  });
  ctx += 'REVENUE EN JUEGO: $' + Math.round(pendingRevenueToday) + '\n';
}

// ─── PROYECTOS Y METAS ───
ctx += '\n════════════════════════════════════════\n';
ctx += '🔭 PROYECTOS Y METAS (' + projects.length + ' activos)\n';
ctx += '════════════════════════════════════════\n';

if (criticalProjects > 0) {
  ctx += '🚨 ALERTA: ' + criticalProjects + ' proyectos críticos';
  if (overdueProjects > 0) ctx += ' (' + overdueProjects + ' VENCIDOS)';
  ctx += '\n\n';
}

projects.slice(0, 15).forEach(p => {
  let timeText = '';
  if (p.daysLeft === 9999) timeText = 'sin fecha';
  else if (p.daysLeft < 0) timeText = Math.abs(p.daysLeft) + 'd vencido';
  else if (p.daysLeft === 0) timeText = 'HOY';
  else timeText = p.daysLeft + 'd restantes';

  ctx += p.urgency.split(' ')[0] + ' ' + p.icon + ' ' + p.name + ' (' + timeText + ')\n';
});

if (projects.length > 15) {
  ctx += '... y ' + (projects.length - 15) + ' proyectos más\n';
}

// ─── IMPACTO FINANCIERO ───
ctx += '\n════════════════════════════════════════\n';
ctx += '💰 IMPACTO FINANCIERO\n';
ctx += '════════════════════════════════════════\n';
ctx += '💰 Revenue diario objetivo: $' + Math.round(DAILY_REVENUE_VALUE) + '\n';
ctx += '🟢 Protegido hoy: $' + Math.round(protectedRevenueToday) + ' (' + Math.round((protectedRevenueToday/DAILY_REVENUE_VALUE)*100) + '%)\n';
ctx += '🔴 Perdido hoy: $' + Math.round(lostRevenueToday) + ' (' + Math.round((lostRevenueToday/DAILY_REVENUE_VALUE)*100) + '%)\n';
ctx += '🟡 En juego: $' + Math.round(pendingRevenueToday) + ' (' + Math.round((pendingRevenueToday/DAILY_REVENUE_VALUE)*100) + '%)\n';
ctx += '💀 Perdido en el mes: $' + Math.round(monthRevenueLost) + '\n';
ctx += '💰 Protegido en el mes: $' + Math.round(monthRevenueProtected) + '\n';

// ─── RACHAS Y TENDENCIA ───
ctx += '\n════════════════════════════════════════\n';
ctx += '📈 RACHAS, TENDENCIA Y RENDIMIENTO MES\n';
ctx += '════════════════════════════════════════\n';
ctx += '🔥 Racha actual: ' + streak + ' días (≥70%)\n';
ctx += '🏆 Mejor racha: ' + bestStreak + ' días\n';
ctx += '📊 Promedio 7 días: ' + trend7avg + '%\n';
ctx += '📈 Dirección: ' + trendDirection + '\n\n';

last7.forEach(d => {
  const icon = d.pct >= 80 ? '🟢' : d.pct >= 60 ? '🟡' : '🔴';
  ctx += icon + ' Día ' + d.day + ': ' + d.pct + '%\n';
});

// Rendimiento por categoría
ctx += '\nPor categoría (mes):\n';
Object.entries(catStats).forEach(([cat, s]) => {
  const pct = s.t > 0 ? Math.round((s.d / s.t) * 100) : 0;
  const emoji = cat === 'matutino' ? '🌅' : cat === 'business' ? '💼' : '🌙';
  ctx += emoji + ' ' + cat.toUpperCase() + ': ' + pct + '% (' + s.d + '/' + s.t + ')\n';
});

ctx += '\nGlobal mes: Simple ' + globalPct + '% | Ponderado ' + globalWeightedPct + '%\n';

// Top fallas
ctx += '\nTop 5 fallas del mes:\n';
topFails.forEach(([n, c]) => {
  const config = HABITS_CONFIG.find(h => h.name.includes(n.split(' ')[0]));
  const rev = config ? Math.round(c * config.revenueImpact * DAILY_REVENUE_VALUE) : 0;
  ctx += '⚠️ ' + n + ': ' + c + ' fallas ($' + rev + ' perdido)\n';
});

// ═══════════════════════════════════════════════════════════════════════════
// RETORNAR
// ═══════════════════════════════════════════════════════════════════════════

return [{
  json: {
    analysisPrompt: 'CONSULTA: "' + (originData.query || 'reporte') + '"\n\n' + ctx,
    query: originData.query || 'reporte',
    source: originData.source || 'manual',
