    projectsCount: projects.length,
    criticalProjects,
    overdueProjects,
    currentMonth, prevMonth, currentYear,
    sheetId: '1KpErnuxfLRCh1RmRoevLOLFeoYpSSzedSjGNcz7Jyjw',
    chatId: '-1003688744736'
  }
}];

